// EDTMRS - Sidebar Navigation
import React from 'react';
import { NavLink } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';

const navItems = [
  { path: '/',          icon: '⬡', label: 'Dashboard'      },
  { path: '/devices',   icon: '⊞', label: 'Device Monitor'  },
  { path: '/endpoints', icon: '◈', label: 'Endpoints'       },
  { path: '/alerts',    icon: '⚠', label: 'Alerts'          },
  { path: '/policy',    icon: '⛨', label: 'Policy Manager'  },
];

export default function Sidebar({ alertCount = 0 }) {
  const { user, logout } = useAuth();

  return (
    <aside className="fixed left-0 top-0 h-full w-60 bg-[#0f1629] border-r border-[#1e2d4d] flex flex-col z-40">
      {/* Logo */}
      <div className="px-6 py-5 border-b border-[#1e2d4d]">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-lg bg-blue-600 flex items-center justify-center text-white font-bold text-sm">E</div>
          <div>
            <div className="text-white font-bold text-sm tracking-wide">EDTMRS</div>
            <div className="text-gray-500 text-[10px] tracking-widest uppercase">v3.0 | Threat Monitor</div>
          </div>
        </div>
      </div>

      {/* Nav */}
      <nav className="flex-1 px-3 py-4 space-y-1">
        {navItems.map((item) => (
          <NavLink
            key={item.path}
            to={item.path}
            end={item.path === '/'}
            className={({ isActive }) =>
              `flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-all ${
                isActive
                  ? 'bg-blue-600/20 text-blue-400 border border-blue-500/30'
                  : 'text-gray-400 hover:text-gray-200 hover:bg-white/5'
              }`
            }
          >
            <span className="text-base">{item.icon}</span>
            <span>{item.label}</span>
            {item.label === 'Alerts' && alertCount > 0 && (
              <span className="ml-auto bg-red-500 text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full animate-pulse">
                {alertCount > 99 ? '99+' : alertCount}
              </span>
            )}
          </NavLink>
        ))}
      </nav>

      {/* User info */}
      <div className="px-4 py-4 border-t border-[#1e2d4d]">
        <div className="flex items-center gap-3 mb-3">
          <div className="w-8 h-8 rounded-full bg-blue-600/30 border border-blue-500/40 flex items-center justify-center text-blue-400 font-bold text-sm">
            {user?.username?.[0]?.toUpperCase() || 'A'}
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-white text-sm font-medium truncate">{user?.username}</div>
            <div className="text-gray-500 text-xs capitalize">{user?.role}</div>
          </div>
        </div>
        <button
          onClick={logout}
          className="w-full text-left px-3 py-2 text-sm text-gray-400 hover:text-red-400 hover:bg-red-500/10 rounded-lg transition-all"
        >
          ⇥ Sign Out
        </button>
      </div>

      {/* Status bar */}
      <div className="px-4 py-2 bg-emerald-500/10 border-t border-emerald-500/20">
        <div className="flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-emerald-400 animate-pulse" />
          <span className="text-emerald-400 text-xs font-medium">System Active</span>
        </div>
      </div>
    </aside>
  );
}
